def _calculate_liquidity_score(self, features: PriceFeatures) -> float:
    """Рассчитать скор ликвидности (0-1) используя централизованную логику."""
    try:
        # Используем централизованный анализатор
        score_obj = self.price_analytics.calculate_liquidity(
            listings_count=int(features.market_depth),
            min_price=Decimal(str(features.price_min_7d)) if features.price_min_7d > 0 else Decimal(str(features.current_price)),
            max_price=Decimal(str(features.price_max_7d)) if features.price_max_7d > 0 else Decimal(str(features.current_price)),
            avg_price=Decimal(str(features.price_mean_7d)) if features.price_mean_7d > 0 else Decimal(str(features.current_price)),
        )
        return float(score_obj.score) / 100.0
    except Exception:
        # Fallback к старой логике если данные некорректны
        if features.avg_sales_per_day >= 10:
            base_score = 1.0
        elif features.avg_sales_per_day >= 5:
            base_score = 0.8
        elif features.avg_sales_per_day >= 2:
            base_score = 0.6
        elif features.avg_sales_per_day >= 1:
            base_score = 0.4
        else:
            base_score = 0.2

        depth_factor = min(features.market_depth / 50, 1.0)
        return base_score * 0.7 + depth_factor * 0.3

